import UIKit

class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private init() {}
    
    func handleUniversalLink(_ url: URL) -> Bool {
        // Validate host and path
        guard let host = url.host, isValidHost(host) else {
            return false
        }
        
        guard let path = url.path, isValidPath(path) else {
            return false
        }
        
        // Extract parameters
        guard let promoCode = extractParameter(from: url, forKey: "code"),
              let discountString = extractParameter(from: url, forKey: "discount"),
              let discount = Int(discountString),
              isValidDiscount(discount) else {
            return false
        }
        
        // Apply promo to user account
        applyPromoCode(promoCode, discount: discount)
        return true
    }
    
    private func isValidHost(_ host: String) -> Bool {
        return host == "myapp.com"
    }
    
    private func isValidPath(_ path: String) -> Bool {
        return path == "/promo"
    }
    
    private func extractParameter(from url: URL, forKey key: String) -> String? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let queryItems = components.queryItems else {
            return nil
        }
        
        return queryItems.first { $0.name == key }?.value
    }
    
    private func isValidDiscount(_ discount: Int) -> Bool {
        return discount >= 0 && discount <= 100
    }
    
