        // Apply to user account
        UserDefaults.standard.set(code, forKey: "activePromoCode")
        UserDefaults.standard.set(discount, forKey: "activePromoDiscount")
        
        // Notify app of promotion
        NotificationCenter.default.post(name: NSNotification.Name("PromoApplied"), object: nil)
    }
    
    private func isValidPromoCode(_ code: String) -> Bool {
        // Basic validation - only alphanumeric characters and hyphens
        let validCharacters = CharacterSet.alphanumerics.union(CharacterSet(charactersIn: "-"))
        return !code.isEmpty && code.rangeOfCharacter(from: validCharacters.inverted) == nil
    }
